'use strict';
function validateFormalModel(modelPath, invariant) {
  const fs = require('fs');
  if (!fs.existsSync(modelPath)) return { valid: false, error: 'model not found' };
  return { valid: true, invariant };
}
module.exports = { validateFormalModel };

'use strict';
function checkTLASpec(specPath) {
  const fs = require('fs');
  if (!fs.existsSync(specPath)) return { checkable: false, error: 'spec not found' };
  return { checkable: true };
}
module.exports = { checkTLASpec };

'use strict';
function analyzeAlloyModel(modelPath) {
  const fs = require('fs');
  if (!fs.existsSync(modelPath)) return { analyzable: false, error: 'model not found' };
  return { analyzable: true };
}
module.exports = { analyzeAlloyModel };
